 85→    cache_creation_tokens: data.cacheCreationTokens,
 86→    cache_read_tokens: data.cacheReadTokens,
 87→    cost_usd: costUsd,
 88→    latency_ms: Math.round(data.latencyMs),
 89→    stop_reason: data.stopReason ?? "end_turn",
 90→    created_at: new Date(),
 91→  };
 92→
 93→  // Set workspace directly on the trace node when known
 94→  if (data.workspaceId) {
 95→    content.workspace = new RecordId("workspace", data.workspaceId);
 96→  }
 97→
 98→  // Set actor directly on the trace node (Brain auth mode)
 99→  if (data.identityId) {
100→    content.actor = new RecordId("identity", data.identityId);
101→  }
102→
103→  if (data.requestId) {
104→    content.request_id = data.requestId;
105→  }
106→
107→  // Store intelligence metadata in FLEXIBLE input field
108→  if (data.intelligenceMetadata) {
109→    content.input = {
110→      brain_context_injected: data.intelligenceMetadata.brain_context_injected,
111→      brain_context_decisions: data.intelligenceMetadata.brain_context_decisions,
112→      brain_context_learnings: data.intelligenceMetadata.brain_context_learnings,
113→      brain_context_observations: data.intelligenceMetadata.brain_context_observations,
114→      brain_context_tokens_est: data.intelligenceMetadata.brain_context_tokens_est,
115→    };
116→  }
117→
118→  // Store response content in FLEXIBLE output field (opaque capture per ADR-051)
119→  if (data.responseContent) {
120→    content.output = data.responseContent;
121→  }
122→
123→  if (data.policyDecision) {
