128→export function buildUpstreamHeaders(request: Request, authMode: AuthMode): Headers {
129→  const headers = new Headers();
130→
131→  for (const name of FORWARDED_HEADERS) {
132→    const value = request.headers.get(name);
133→    if (value) headers.set(name, value);
134→  }
135→
136→  if (authMode.mode === "brain" && authMode.serverApiKey) {
137→    // Brain auth with server-held API key: inject it, do not forward client auth
138→    headers.set("x-api-key", authMode.serverApiKey);
139→  } else {
140→    // Direct auth: forward client's auth headers as-is
141→    const xApiKey = request.headers.get("x-api-key");
142→    const authHeader = request.headers.get("authorization");
143→    if (xApiKey) headers.set("x-api-key", xApiKey);
144→    if (authHeader) headers.set("authorization", authHeader);
145→  }
146→
147→  return headers;
148→}
