234→type StreamContext = {
235→  model?: string;
236→  inputTokens: number;
237→  outputTokens: number;
238→  cacheCreationTokens: number;
239→  cacheReadTokens: number;
240→  stopReason?: string;
241→};
242→
243→function extractSSEUsage(buffer: string, ctx: StreamContext): string {
244→  const lines = buffer.split("\n");
245→  const remainder = lines.pop() ?? "";
246→
247→  for (const line of lines) {
248→    if (!line.startsWith("data: ")) continue;
249→    const data = line.slice(6);
250→    if (data === "[DONE]") continue;
251→
252→    try {
253→      const event = JSON.parse(data);
254→
255→      if (event.type === "message_start" && event.message?.usage) {
256→        ctx.inputTokens = event.message.usage.input_tokens ?? 0;
257→        ctx.cacheCreationTokens = event.message.usage.cache_creation_input_tokens ?? 0;
258→        ctx.cacheReadTokens = event.message.usage.cache_read_input_tokens ?? 0;
259→        ctx.model = event.message.model ?? ctx.model;
260→      }
261→
262→      if (event.type === "message_delta") {
263→        if (event.usage?.output_tokens) {
264→          ctx.outputTokens = event.usage.output_tokens;
265→        }
266→        if (event.delta?.stop_reason) {
267→          ctx.stopReason = event.delta.stop_reason;
268→        }
269→      }
270→    } catch {
271→      // partial JSON or non-JSON data line — skip
272→    }
273→  }
274→
275→  return remainder;
276→}
