331→// ---------------------------------------------------------------------------
332→
333→const DECISION_WEIGHT = 1.0;
334→const LEARNING_WEIGHT = 0.8;
335→const OBSERVATION_WEIGHT = 0.7;
336→
337→async function loadCandidatePool(
338→  surreal: ServerDependencies["surreal"],
339→  workspaceId: string,
340→): Promise<CachedCandidatePool> {
341→  const workspaceRecord = new RecordId("workspace", workspaceId);
342→
343→  type DecisionRow = { id: RecordId; summary: string };
344→  type LearningRow = { id: RecordId; text: string };
345→  type ObservationRow = { id: RecordId; text: string };
346→
347→  // Single round-trip: no embedding fields fetched (02-01)
348→  const results = await surreal.query<[DecisionRow[], LearningRow[], ObservationRow[]]>(
349→    `SELECT id, summary FROM decision WHERE workspace = $ws AND status = 'confirmed' LIMIT 50;
350→     SELECT id, text FROM learning WHERE workspace = $ws AND status = 'active' LIMIT 30;
351→     SELECT id, text FROM observation WHERE workspace = $ws AND status = 'open' AND severity IN ['conflict', 'warning'] AND source_agent != 'llm-proxy' LIMIT 20;`,
352→    { ws: workspaceRecord },
353→  );
354→
355→  function toCandidates<T extends { id: RecordId }>(
356→    rows: T[],
357→    type: CandidateItem["type"],
358→    weight: number,
359→    textFn: (row: T) => string,
360→  ): CandidateItem[] {
361→    return rows.map((row) => ({
362→      id: (row.id as RecordId).id as string,
363→      type,
364→      text: textFn(row),
365→      weight,
366→    }));
367→  }
368→
369→  const decisions = toCandidates(results[0] ?? [], "decision", DECISION_WEIGHT, (d) => d.summary);
370→  const learnings = toCandidates(results[1] ?? [], "learning", LEARNING_WEIGHT, (l) => l.text);
371→  const observations = toCandidates(results[2] ?? [], "observation", OBSERVATION_WEIGHT, (o) => o.text);
372→
373→  return {
374→    decisions,
375→    learnings,
376→    observations,
377→    populatedAt: Date.now(),
378→  };
379→}
