381→// ---------------------------------------------------------------------------
382→// Context Injection Pipeline (orchestrator)
383→// ---------------------------------------------------------------------------
384→
385→type ContextInjectionResult = {
386→  readonly body: string;
387→  readonly injectionResult?: InjectionResult;
388→};
389→
390→async function runContextInjection(
391→  deps: ServerDependencies,
392→  workspaceId: string,
393→  parsedBody: ParsedBody,
394→  originalBody: string,
395→  contextCache: ContextCache,
396→  intelligenceConfig: IntelligenceConfig,
397→  fetchRecentChanges?: FetchRecentChangesByTime,
398→  searchContextByBm25?: SearchContextByBm25,
399→): Promise<ContextInjectionResult> {
400→  if (!intelligenceConfig.contextInjectionEnabled) {
401→    return { body: originalBody };
402→  }
403→
404→  // 1. Extract last user message text (for BM25 query)
405→  const messages = parsedBody.messages ?? [];
406→  let lastUserMessage: { role: string; content: string } | undefined;
407→  for (let i = messages.length - 1; i >= 0; i--) {
408→    if (messages[i].role === "user") { lastUserMessage = messages[i]; break; }
409→  }
410→  if (!lastUserMessage) {
411→    return { body: originalBody };
412→  }
413→
414→  const queryText = lastUserMessage.content;
415→  const now = new Date();
416→
417→  // 2. Search context candidates via BM25 fulltext (no embeddings)
418→  let selectedCandidates;
419→  if (searchContextByBm25) {
420→    // BM25 path: query-time search ranked by relevance + recency
421→    const bm25Candidates = await searchContextByBm25(queryText, workspaceId, 100);
422→
423→    if (bm25Candidates.length === 0) {
424→      // Fallback: load cached pool without ranking (weight-based)
425→      const pool = await loadFallbackPool(deps, workspaceId, contextCache);
426→      if (!pool) return { body: originalBody };
427→      const allCandidates = [...pool.decisions, ...pool.learnings, ...pool.observations];
428→      const ranked = allCandidates.map((c) => ({ id: c.id, type: c.type, text: c.text, score: c.weight }));
429→      selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
430→    } else {
431→      log.info("proxy.context_injection.bm25_search", "BM25 context search completed", {
432→        workspace_id: workspaceId,
433→        candidates: bm25Candidates.length,
434→      });
435→      const ranked = rankByBm25WithRecency(bm25Candidates, now);
436→      selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
437→    }
438→  } else {
439→    // Legacy fallback: cached pool with weight-based ranking (no embeddings)
440→    const pool = await loadFallbackPool(deps, workspaceId, contextCache);
441→    if (!pool) return { body: originalBody };
442→    const allCandidates: ContextCandidate[] = [...pool.decisions, ...pool.learnings, ...pool.observations];
443→    const ranked = allCandidates.map((c) => ({ id: c.id, type: c.type, text: c.text, score: c.weight }));
444→    selectedCandidates = selectWithinBudget(ranked, intelligenceConfig.contextInjectionTokenBudget);
445→  }
446→
447→  if (selectedCandidates.length === 0) {
448→    return { body: originalBody };
449→  }
450→
451→  // 3. Build XML block
452→  const brainContextXml = buildBrainContextXml(selectedCandidates);
453→
454→  // 4. Inject into system prompt
455→  const injectionResult = injectBrainContext(parsedBody.system, brainContextXml);
456→
457→  // 5. Fetch and inject recent changes by time window (no embeddings, no BM25)
458→  let enrichedSystem = injectionResult.system;
459→  if (fetchRecentChanges) {
460→    try {
461→      const timeWindowMs = 24 * 60 * 60 * 1000; // 24-hour window
462→      const cutoff = buildTimeWindowCutoff(now, timeWindowMs);
463→      const recentCandidates = await fetchRecentChanges(workspaceId, cutoff, 20);
464→      const classified = classifyByAge(recentCandidates, now);
465→      const recentChangesXml = buildRecentChangesXml(classified);
466→      if (recentChangesXml) {
467→        enrichedSystem = injectRecentChanges(enrichedSystem, recentChangesXml);
468→      }
469→    } catch (error) {
470→      // Fail-open: log and continue without recent changes
471→      log.warn("proxy.context_injection.recent_changes_failed", "Recent changes fetch failed", {
472→        workspace_id: workspaceId,
473→        error: String(error),
474→      });
475→    }
476→  }
477→
478→  // 6. Build modified request body
479→  const modifiedBody = {
480→    ...parsedBody,
481→    system: enrichedSystem,
482→  };
483→
484→  return {
485→    body: JSON.stringify(modifiedBody),
486→    injectionResult,
487→  };
488→}
