490→/** Load fallback candidate pool from cache or DB (legacy path). */
491→async function loadFallbackPool(
492→  deps: ServerDependencies,
493→  workspaceId: string,
494→  contextCache: ContextCache,
495→): Promise<CachedCandidatePool | undefined> {
496→  let fromCache = false;
497→  const pool = contextCache.has(workspaceId)
498→    ? (fromCache = true, contextCache.get(workspaceId)!)
499→    : await loadCandidatePool(deps.surreal, workspaceId);
500→
501→  if (!fromCache) {
502→    contextCache.set(workspaceId, pool);
503→  }
504→
505→  const total = pool.decisions.length + pool.learnings.length + pool.observations.length;
506→  if (total === 0) return undefined;
507→
508→  log.info("proxy.context_injection.pool_loaded", "Candidate pool loaded", {
509→    workspace_id: workspaceId,
510→    decisions: pool.decisions.length,
511→    learnings: pool.learnings.length,
512→    observations: pool.observations.length,
513→    total,
514→    cached: fromCache,
515→  });
516→
517→  return pool;
518→}
