623→
624→export function createAnthropicProxyHandler(
625→  deps: ServerDependencies,
626→): (request: Request) => Promise<Response> {
627→  const workspaceCache: WorkspaceCache = new Map();
628→  const rateLimiterState: RateLimiterState = createRateLimiterState();
629→  const spendCache: SpendCache = new Map();
630→  const noPolicyWarnedWorkspaces = new Set<string>();
631→  const contextCache: ContextCache = createContextCache(300); // default TTL, overridden per-workspace
632→
633→  // Proxy auth: per-handler cache + DB lookup function (not module-level singletons)
634→  const proxyTokenCache: TokenCache = createTokenCache();
635→  const lookupProxyToken: LookupProxyToken = createLookupProxyToken(deps.surreal);
636→
637→  // Context search adapters (02-01: BM25 for context, 02-03: time-based for recent changes)
638→  const fetchRecentChanges: FetchRecentChangesByTime = createFetchRecentChangesByTime(deps.surreal);
639→  const searchContextByBm25: SearchContextByBm25 = createSearchContextByBm25(deps.surreal);
640→
641→  // Periodic pruning of stale rate limiter entries to prevent unbounded Map growth.
642→  // unref() ensures this interval does not keep the process alive on shutdown.
643→  const pruneInterval = setInterval(
644→    () => {
645→      pruneStaleEntries(rateLimiterState, Date.now());
646→      const nowMs = Date.now();
647→      for (const [key, entry] of proxyTokenCache) {
648→        if (nowMs >= entry.expiresAt) proxyTokenCache.delete(key);
649→      }
650→    },
651→    5 * 60 * 1000,
652→  );
653→  pruneInterval.unref();
654→
655→  const anthropicApiUrl = deps.config.anthropicApiUrl;
656→
657→  return async (request: Request): Promise<Response> => {
658→    const startedAt = performance.now();
659→    const url = new URL(request.url);
660→    const upstreamPath = url.pathname.replace(/^\/proxy\/llm\/anthropic/, "");
661→    const upstreamUrl = `${anthropicApiUrl}${upstreamPath}`;
662→    const isCountTokens = isCountTokensRequest(url.pathname);
663→    const span = trace.getActiveSpan();
664→    const traceId = span?.spanContext().traceId;
665→    const requestMode = request.headers.get("X-Brain-Auth") ? "brain" : "direct";
666→
667→    const setSpanAttributes = (attributes: Record<string, string | number | boolean | undefined>) => {
668→      if (!span) return;
669→      for (const [key, value] of Object.entries(attributes)) {
670→        if (value !== undefined) {
671→          span.setAttribute(key, value);
672→        }
673→      }
674→    };
675→
676→    let currentStage: ProxyStage = "parse_request";
677→    const setStage = (stage: ProxyStage) => {
678→      currentStage = stage;
679→      setSpanAttributes({ "proxy.stage": stage });
680→    };
681→    setStage("parse_request");
682→
683→    setSpanAttributes({
684→      "proxy.path": upstreamPath,
685→      "proxy.upstream_url": upstreamUrl,
686→      "proxy.is_count_tokens": isCountTokens,
687→      "proxy.request_mode": requestMode,
688→    });
689→
690→    // --- Step 1: Parse request body (malformed body forwarded as-is) ---
691→    let body: string;
692→    let parsed: ParsedBody | undefined;
693→    let isStreaming = false;
694→    let identitySignals:
695→      | ReturnType<typeof resolveIdentity>
696→      | undefined;
697→
698→    try {
699→      body = await request.text();
700→      parsed = tryParseRequestBody(body);
701→      isStreaming = parsed?.stream === true;
702→      setSpanAttributes({
703→        "proxy.request_body_parsed": parsed !== undefined,
704→        "proxy.request_body_bytes": body.length,
705→        "proxy.request_model": parsed?.model,
706→        "proxy.is_streaming": isStreaming,
707→      });
708→
709→      // --- Step 1.5: Brain auth resolution (dual-mode) ---
710→      setStage("resolve_auth");
711→      let brainAuthResult: ProxyAuthResult | undefined;
712→      let authMode: AuthMode = { mode: "direct" };
713→
714→      try {
715→        brainAuthResult = await resolveProxyAuth(
716→          request.headers,
717→          lookupProxyToken,
718→          proxyTokenCache,
719→        );
720→      } catch (error) {
721→        if (error instanceof ProxyAuthError) {
722→          setSpanAttributes({
723→            "proxy.error.type": "authentication_error",
724→            "proxy.error.stage": currentStage,
725→          });
726→          log.warn("proxy.anthropic.auth_failed", "Brain auth failed", {
727→            stage: currentStage,
728→            error: error.message,
729→          });
730→          return jsonResponse(
731→            buildProxyErrorPayload(
732→              "authentication_error",
733→              error.message,
734→              { stage: currentStage, traceId },
735→            ),
736→            401,
737→          );
738→        }
739→        throw error;
740→      }
741→
742→      if (brainAuthResult) {
743→        // Brain auth mode: use server API key if available, otherwise forward client auth headers
744→        authMode = { mode: "brain", serverApiKey: deps.config.anthropicApiKey };
745→      }
746→      setSpanAttributes({ "proxy.auth_mode": authMode.mode });
747→
748→      // --- Step 2: Identity resolution ---
749→      setStage("resolve_identity");
750→      // In Brain auth mode, workspace comes from the token (not from headers)
751→      identitySignals = resolveIdentity({
752→        metadataUserId: parsed?.metadata?.user_id,
753→        workspaceHeader: brainAuthResult?.workspaceId ?? (request.headers.get("X-Brain-Workspace") ?? undefined),
754→        taskHeader: request.headers.get("X-Brain-Task") ?? undefined,
755→        agentTypeHeader: request.headers.get("X-Brain-Agent-Type") ?? undefined,
756→        sessionHeader: request.headers.get("X-Brain-Session") ?? undefined,
757→        proxyTokenIdentityId: brainAuthResult?.identityId,
758→        userAgent: request.headers.get("User-Agent") ?? undefined,
759→      });
760→      setSpanAttributes({
761→        "proxy.workspace_id": identitySignals.workspaceId,
762→        "proxy.task_id": identitySignals.taskId,
763→        "proxy.agent_type": identitySignals.agentType,
764→        "proxy.session_header": identitySignals.sessionHeaderId,
765→      });
766→
767→      // --- Step 3: Session ID resolution ---
768→      setStage("resolve_session");
769→      // resolveSessionId returns either the header PK or the external Claude Code
770→      // session UUID. Resolve to the actual agent_session PK via DB lookup.
771→      const rawSessionId = resolveSessionId(identitySignals);
772→      let effectiveSessionId = rawSessionId
773→        ? await resolveAgentSessionId(deps.surreal, rawSessionId)
774→        : undefined;
775→      setSpanAttributes({
776→        "proxy.session_id.raw": rawSessionId,
777→        "proxy.session_id.effective": effectiveSessionId,
778→      });
779→
780→      // --- Step 3.5: Session hash fallback ---
781→      // When no explicit session signal exists, derive a deterministic session
782→      // identity from request content (system_prompt + first_user_message).
783→      if (!effectiveSessionId && identitySignals.workspaceId && parsed) {
784→        const sessionHashInput: SessionHashInput = {
785→          systemPrompt: typeof parsed.system === "string" ? parsed.system : undefined,
786→          systemPromptBlocks: Array.isArray(parsed.system) ? parsed.system : undefined,
787→          messages: parsed.messages ?? [],
788→        };
789→        const sessionHash = resolveSessionHash(sessionHashInput);
790→
791→        if (sessionHash) {
792→          try {
793→            const upsertedSessionId = await upsertProxySession(
794→              {
795→                sessionId: sessionHash.sessionId,
796→                workspaceId: identitySignals.workspaceId,
797→                agent: resolveAgentName(identitySignals),
798→              },
799→              { surreal: deps.surreal },
800→            );
801→            if (upsertedSessionId) {
802→              effectiveSessionId = upsertedSessionId;
803→              setSpanAttributes({ "proxy.session_id.effective": effectiveSessionId });
804→            }
805→          } catch (error) {
806→            log.warn("proxy.anthropic.session_hash_upsert_failed", "Session hash upsert failed — continuing without session link", {
807→              error: String(error),
808→            });
809→          }
810→        }
811→      }
812→
813→      // --- Workspace validation (non-blocking) ---
814→      setStage("validate_workspace");
815→      if (identitySignals.workspaceId) {
816→        const isValid = await validateWorkspace(
817→          deps.surreal,
818→          identitySignals.workspaceId,
819→          workspaceCache,
820→        );
821→        setSpanAttributes({ "proxy.workspace_valid": isValid });
822→        if (!isValid) {
823→          log.warn("proxy.anthropic.invalid_workspace", "Workspace not found in database", {
824→            workspaceId: identitySignals.workspaceId,
825→          });
826→        }
827→      }
828→
829→      // --- Step 4: Policy evaluation ---
