138→export function setupAcceptanceSuite(
139→  suiteName: string,
140→  options?: AcceptanceSuiteOptions,
141→): () => AcceptanceTestRuntime {
142→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
143→  const namespace = `accept_${runId}`;
144→  const suiteSlug = suiteName
145→    .toLowerCase()
146→    .replace(/[^a-z0-9]+/g, "_")
147→    .replace(/^_+|_+$/g, "");
148→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
149→
150→  let runtime: AcceptanceTestRuntime | undefined;
151→  let server: ReturnType<typeof Bun.serve> | undefined;
152→  let runtimeSurreal: Surreal | undefined;
153→  let analyticsSurreal: Surreal | undefined;
154→  let inflight: InflightTracker | undefined;
155→  let setupSucceeded = false;
156→
157→  beforeAll(async () => {
158→    const surreal = new Surreal();
159→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
160→    await withTimeout(
161→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
162→      10_000,
163→      "authenticate with SurrealDB",
164→    );
165→
166→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
167→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
168→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
169→    await withTimeout(
170→      () => surreal.use({ namespace, database }),
171→      10_000,
172→      "switch to test namespace/database",
173→    );
174→
175→    await withTimeout(() => applyTestSchema(surreal), 20_000, "apply schema");
176→
177→    // Reserve a port so betterAuth gets the real URL at init time
178→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
179→    const reservedPort = tempServer.port;
180→    tempServer.stop(true);
181→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
182→
183→    const config: ServerConfig = {
184→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
185→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
186→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
187→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
188→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
189→      embeddingModelId: requireTestEnv("EMBEDDING_MODEL"),
190→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
191→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
192→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
193→      surrealUrl,
194→      surrealUsername,
195→      surrealPassword,
196→      surrealNamespace: namespace,
197→      surrealDatabase: database,
198→      port: reservedPort,
199→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
200→      betterAuthUrl: baseUrl,
201→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
202→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
203→      observerModelId: process.env.OBSERVER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
204→      scorerModelId: process.env.SCORER_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
205→      anthropicApiUrl: process.env.ANTHROPIC_API_URL?.trim() || "https://api.anthropic.com",
206→      ...(process.env.ANTHROPIC_API_KEY?.trim() ? { anthropicApiKey: process.env.ANTHROPIC_API_KEY.trim() } : {}),
207→      inferenceProvider: "openrouter",
208→      selfHosted: false,
209→      worktreeManagerEnabled: false,
210→      ...options?.configOverrides,
211→    };
212→
213→    const deps = await createRuntimeDependencies(config);
214→    runtimeSurreal = deps.surreal;
215→    analyticsSurreal = deps.analyticsSurreal;
216→    inflight = createInflightTracker();
217→
218→    const serverDeps: ServerDependencies = {
219→      config,
220→      surreal: deps.surreal,
221→      analyticsSurreal: deps.analyticsSurreal,
222→      auth: deps.auth,
223→      chatAgentModel: deps.chatAgentModel,
224→      extractionModel: deps.extractionModel,
225→      pmAgentModel: deps.pmAgentModel,
226→      analyticsAgentModel: deps.analyticsAgentModel,
227→      embeddingModel: deps.embeddingModel,
228→      observerModel: deps.observerModel,
229→      scorerModel: deps.scorerModel,
230→      sse: createSseRegistry(),
231→      inflight,
232→      asSigningKey: deps.asSigningKey,
233→      nonceCache: createNonceCache(),
234→    };
235→
236→    server = createBrainServer(serverDeps);
237→    const port = server.port;
238→
239→    // Start reactive coordination layer: LIVE SELECT -> Feed SSE Bridge -> SSE Registry
240→    const liveSelectManager = createLiveSelectManager({ surreal: deps.surreal });
241→    const feedSseBridge = createFeedSseBridge({
242→      liveSelectManager,
243→      sseRegistry: serverDeps.sse,
244→    });
245→    feedSseBridge.subscribeAll();
246→
247→    // Agent Coordinator is created inside createBrainServer (called above).
248→    // In prod, DEFINE EVENT webhooks call the coordinator endpoint.
249→    // In acceptance tests, observations trigger the coordinator via the same HTTP endpoint.
250→
251→    inflight.track(
252→      liveSelectManager.start().catch(() => undefined),
253→    );
254→
255→    runtime = { baseUrl, surreal, namespace, database, port };
256→    setupSucceeded = true;
257→  }, 60_000);
258→
259→  afterAll(async () => {
260→    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
261→    if (inflight) {
262→      await inflight.drain(15_000);
263→    }
264→
265→    if (server) {
266→      server.stop(true);
267→    }
268→
269→    if (runtimeSurreal) {
270→      await runtimeSurreal.close().catch(() => undefined);
271→    }
272→    if (analyticsSurreal) {
273→      await analyticsSurreal.close().catch(() => undefined);
274→    }
275→
276→    if (!runtime) {
277→      return;
278→    }
279→
280→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
281→      try {
282→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
283→      } catch {
284→        // Best effort cleanup.
285→      }
286→
287→      try {
288→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
289→      } catch {
290→        // Best effort cleanup.
291→      }
292→    }
293→
294→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
295→  }, 20_000);
296→
297→  return () => {
298→    if (!runtime) {
299→      throw new Error("Acceptance runtime requested before suite setup completed");
300→    }
301→    return runtime;
302→  };
303→}
