618→      dpop_jwk_thumbprint: keyPair.thumbprint,
619→      action_spec: { provider: "test", action: "broad_access", params: {} },
620→      trace_id: traceRecord,
621→      requester: identityRecord,
622→      workspace: workspaceRecord,
623→      evaluation: {
624→        decision: "APPROVE",
625→        risk_score: 0,
626→        reason: "Pre-authorized for testing",
627→        evaluated_at: new Date(),
628→        policy_only: true,
629→      },
630→      created_at: new Date(),
631→    },
632→  });
633→
634→  // Request DPoP-bound access token from Custom AS
635→  const tokenUri = `${baseUrl}/api/auth/token`;
636→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
637→
638→  const tokenRes = await fetch(tokenUri, {
639→    method: "POST",
640→    headers: {
641→      "Content-Type": "application/json",
642→      DPoP: dpopProof,
643→    },
644→    body: JSON.stringify({
645→      grant_type: "urn:brain:intent-authorization",
646→      intent_id: intentId,
647→      authorization_details: broadActions,
648→    }),
649→  });
650→
651→  if (!tokenRes.ok) {
652→    const body = await tokenRes.text();
653→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
654→  }
655→
656→  const { access_token } = (await tokenRes.json()) as { access_token: string };
657→
658→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
659→    const method = options?.method ?? "POST";
660→    const requestUri = `${baseUrl}${path}`;
661→    const proof = await createDPoPProof(keyPair, method, requestUri);
662→
663→    return fetch(requestUri, {
664→      method,
665→      headers: {
666→        "Content-Type": "application/json",
667→        Authorization: `DPoP ${access_token}`,
668→        DPoP: proof,
669→      },
670→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
671→    });
672→  };
673→
674→  return {
675→    ...user,
676→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
677→    mcpFetch,
678→    accessToken: access_token,
679→    keyPair,
680→    workspaceId,
681→    identityId,
682→  };
683→}
