758→// ---------------------------------------------------------------------------
759→
760→function requireTestEnv(name: string): string {
761→  const value = process.env[name];
762→  if (!value || value.trim().length === 0) {
763→    throw new Error(`Acceptance test requires env var ${name}`);
764→  }
765→  return value;
766→}
767→
768→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
769→  return await Promise.race([
770→    callback(),
771→    new Promise<T>((_, reject) => {
772→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
773→    }),
774→  ]);
775→}
