  29→// ---------------------------------------------------------------------------
  30→// Test Model Configuration
  31→// ---------------------------------------------------------------------------
  32→
  33→/**
  34→ * The Anthropic model to use in proxy acceptance tests.
  35→ * Required env var: TEST_PROXY_ANTHROPIC_MODEL
  36→ * Example: claude-haiku-4-5-20251001
  37→ */
  38→function requireTestProxyModel(): string {
  39→  const model = process.env.TEST_PROXY_ANTHROPIC_MODEL?.trim();
  40→  if (!model) {
  41→    throw new Error(
  42→      "TEST_PROXY_ANTHROPIC_MODEL env var is required for proxy acceptance tests. " +
  43→      "Set it to a cheap model like claude-haiku-4-5-20251001.",
  44→    );
  45→  }
  46→  return model;
  47→}
