  51→// ---------------------------------------------------------------------------
  52→// Proxy Request Builders
  53→// ---------------------------------------------------------------------------
  54→
  55→export type ProxyRequestOptions = {
  56→  model: string;
  57→  stream?: boolean;
  58→  maxTokens?: number;
  59→  messages?: Array<{ role: string; content: string }>;
  60→  metadata?: { user_id?: string };
  61→  apiKey?: string;
  62→  workspaceHeader?: string;
  63→  taskHeader?: string;
  64→  agentTypeHeader?: string;
  65→};
  66→
  67→/**
  68→ * Build a proxy request body matching the Anthropic Messages API format.
  69→ */
  70→export function buildProxyRequestBody(options: ProxyRequestOptions): string {
  71→  return JSON.stringify({
  72→    model: options.model,
  73→    max_tokens: options.maxTokens ?? 100,
  74→    stream: options.stream ?? false,
  75→    messages: options.messages ?? [
  76→      { role: "user", content: "Say hello in one word." },
  77→    ],
  78→    ...(options.metadata ? { metadata: options.metadata } : {}),
  79→  });
  80→}
  81→
  82→/**
  83→ * Build headers for a proxy request, including identity headers.
  84→ */
  85→export function buildProxyHeaders(options: ProxyRequestOptions): Record<string, string> {
  86→  const headers: Record<string, string> = {
  87→    "Content-Type": "application/json",
  88→    "anthropic-version": "2023-06-01",
  89→  };
  90→
  91→  if (options.apiKey) {
  92→    headers["x-api-key"] = options.apiKey;
  93→  }
  94→  if (options.workspaceHeader) {
  95→    headers["X-Brain-Workspace"] = options.workspaceHeader;
  96→  }
  97→  if (options.taskHeader) {
  98→    headers["X-Brain-Task"] = options.taskHeader;
  99→  }
 100→  if (options.agentTypeHeader) {
 101→    headers["X-Brain-Agent-Type"] = options.agentTypeHeader;
 102→  }
 103→
 104→  return headers;
 105→}
