 107→/**
 108→ * Retry a fetch call on transient upstream errors (rate limiting).
 109→ * OpenRouter may return 401 or 429 under concurrent load.
 110→ */
 111→async function withUpstreamRetry(
 112→  fn: () => Promise<Response>,
 113→  maxRetries = 2,
 114→): Promise<Response> {
 115→  for (let attempt = 0; attempt <= maxRetries; attempt++) {
 116→    const response = await fn();
 117→    const isTransient = response.status === 429
 118→      || (response.status === 401 && attempt < maxRetries);
 119→    if (!isTransient) return response;
 120→    // Consume body before retry to avoid resource leaks
 121→    await response.text().catch(() => undefined);
 122→    await new Promise(r => setTimeout(r, 1000 * (attempt + 1)));
 123→  }
 124→  return fn();
 125→}
