 127→/**
 128→ * Send a request through the LLM proxy endpoint.
 129→ * Returns the raw Response for flexible assertion.
 130→ */
 131→export async function sendProxyRequest(
 132→  baseUrl: string,
 133→  options: ProxyRequestOptions,
 134→): Promise<Response> {
 135→  const body = buildProxyRequestBody(options);
 136→  const headers = buildProxyHeaders(options);
 137→  const url = `${baseUrl}/proxy/llm/anthropic/v1/messages`;
 138→
 139→  return withUpstreamRetry(() =>
 140→    fetch(url, { method: "POST", headers, body }),
 141→  );
 142→}
