 160→// ---------------------------------------------------------------------------
 161→// SSE Stream Helpers
 162→// ---------------------------------------------------------------------------
 163→
 164→export type SSEEvent = {
 165→  event?: string;
 166→  data: string;
 167→};
 168→
 169→/**
 170→ * Collect all SSE events from a streaming proxy response.
 171→ */
 172→export async function collectProxySSEEvents(response: Response): Promise<SSEEvent[]> {
 173→  if (!response.body) {
 174→    throw new Error("No response body for SSE collection");
 175→  }
 176→
 177→  const reader = response.body.getReader();
 178→  const decoder = new TextDecoder();
 179→  const events: SSEEvent[] = [];
 180→  let buffer = "";
 181→
 182→  try {
 183→    while (true) {
 184→      const { done, value } = await reader.read();
 185→      if (done) break;
 186→
 187→      buffer += decoder.decode(value, { stream: true });
 188→      const segments = buffer.split("\n\n");
 189→      buffer = segments.pop() ?? "";
 190→
 191→      for (const segment of segments) {
 192→        const lines = segment.split("\n");
 193→        let eventType: string | undefined;
 194→        let dataLine: string | undefined;
 195→
 196→        for (const line of lines) {
 197→          if (line.startsWith("event: ")) {
 198→            eventType = line.slice(7);
 199→          } else if (line.startsWith("data: ")) {
 200→            dataLine = line.slice(6);
 201→          }
 202→        }
 203→
 204→        if (dataLine !== undefined) {
 205→          events.push({ event: eventType, data: dataLine });
 206→        }
 207→      }
 208→    }
 209→  } finally {
 210→    reader.releaseLock();
 211→  }
 212→
 213→  return events;
 214→}
