 413→/**
 414→ * Seed an LLM trace directly for testing dashboard/audit scenarios
 415→ * that need pre-existing trace data.
 416→ */
 417→export async function seedLlmTrace(
 418→  surreal: Surreal,
 419→  traceId: string,
 420→  options: {
 421→    model: string;
 422→    input_tokens: number;
 423→    output_tokens: number;
 424→    cost_usd: number;
 425→    latency_ms: number;
 426→    workspaceId: string;
 427→    taskId?: string;
 428→    sessionId?: string;
 429→    stop_reason?: string;
 430→    cache_read_tokens?: number;
 431→    cache_creation_tokens?: number;
 432→    created_at?: Date;
 433→  },
 434→): Promise<string> {
 435→  const traceRecord = new RecordId("trace", traceId);
 436→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
 437→
 438→  // Ensure a test identity exists for the actor field (required by trace schema)
 439→  const actorId = `proxy-test-actor-${options.workspaceId}`;
 440→  const actorRecord = new RecordId("identity", actorId);
 441→  await surreal.query(
 442→    `CREATE $actor CONTENT { name: "proxy-test-system", type: "system", workspace: $ws, created_at: time::now() };`,
 443→    { actor: actorRecord, ws: workspaceRecord },
 444→  ).catch(() => undefined); // Ignore if already exists
 445→
 446→  const traceContent: Record<string, unknown> = {
 447→    type: "llm_call",
 448→    model: options.model,
 449→    input_tokens: options.input_tokens,
 450→    output_tokens: options.output_tokens,
 451→    cache_read_tokens: options.cache_read_tokens ?? 0,
 452→    cache_creation_tokens: options.cache_creation_tokens ?? 0,
 453→    cost_usd: options.cost_usd,
 454→    latency_ms: options.latency_ms,
 455→    stop_reason: options.stop_reason ?? "end_turn",
 456→    workspace: workspaceRecord,
 457→    actor: actorRecord,
 458→    created_at: options.created_at ?? new Date(),
 459→  };
 460→
 461→  // Link session directly on trace record (schema: session TYPE option<record<agent_session>>)
 462→  if (options.sessionId) {
 463→    traceContent.session = new RecordId("agent_session", options.sessionId);
 464→  }
 465→
 466→  await surreal.query(`CREATE $trace CONTENT $content;`, {
 467→    trace: traceRecord,
 468→    content: traceContent,
 469→  });
 470→
 471→  // Create workspace edge
 472→  await surreal.query(
 473→    `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
 474→    { trace: traceRecord, workspace: workspaceRecord },
 475→  );
 476→
 477→  // Create task edge if provided
 478→  if (options.taskId) {
 479→    const taskRecord = new RecordId("task", options.taskId);
 480→    await surreal.query(
 481→      `RELATE $trace->attributed_to->$task SET created_at = time::now();`,
 482→      { trace: traceRecord, task: taskRecord },
 483→    );
 484→  }
 485→
 486→  // Create session edge if provided
 487→  if (options.sessionId) {
 488→    const sessionRecord = new RecordId("agent_session", options.sessionId);
 489→    await surreal.query(
 490→      `RELATE $sess->invoked->$trace SET created_at = time::now();`,
 491→      { trace: traceRecord, sess: sessionRecord },
 492→    );
 493→  }
 494→
 495→  return traceId;
 496→}
