/**
 * Set up a complete tool grant scenario:
 * Creates an mcp_tool + can_use edge for an identity.
 * Reusable across credential, proxy, and governance tests.
 */
export async function seedToolWithGrant(
  surreal: Surreal,
  options: {
    toolId: string;
    toolName: string;
    toolkit: string;
    description: string;
    inputSchema: Record<string, unknown>;
    identityId: string;
    workspaceId: string;
    providerId?: string;
    riskLevel?: "low" | "medium" | "high" | "critical";
    maxCallsPerHour?: number;
  },
): Promise<string> {
  await seedMcpTool(surreal, options.toolId, {
    name: options.toolName,
    toolkit: options.toolkit,
    description: options.description,
    inputSchema: options.inputSchema,
    provider: options.providerId,
    riskLevel: options.riskLevel,
    workspaceId: options.workspaceId,
  });

  await seedCanUseEdge(surreal, options.identityId, options.toolId, {
    maxCallsPerHour: options.maxCallsPerHour,
  });

  return options.toolId;
}

/**
 * Set up a full integration tool scenario:
 * credential_provider + mcp_tool (with provider) + can_use edge + connected_account.
 * Reusable across credential brokerage and integration routing tests.
 */
export async function seedFullIntegrationTool(
  surreal: Surreal,
  options: {
    providerId: string;
    providerName: string;
    authMethod: "oauth2" | "api_key" | "bearer" | "basic";
    toolId: string;
    toolName: string;
    toolkit: string;
    description: string;
    inputSchema: Record<string, unknown>;
    identityId: string;
    workspaceId: string;
    accountId: string;
    // OAuth2-specific
    authorizationUrl?: string;
    tokenUrl?: string;
    clientId?: string;
    clientSecretEncrypted?: string;
    scopes?: string[];
    accessTokenEncrypted?: string;
    refreshTokenEncrypted?: string;
    tokenExpiresAt?: Date;
    // API key-specific
    apiKeyHeader?: string;
    apiKeyEncrypted?: string;
    // Basic-specific
    basicUsername?: string;
    basicPasswordEncrypted?: string;
  },
): Promise<{
  providerId: string;
  toolId: string;
  accountId: string;
}> {
  // 1. Create credential provider
  await seedCredentialProvider(surreal, options.providerId, {
    name: options.providerName,
    displayName: options.providerName,
    authMethod: options.authMethod,
    workspaceId: options.workspaceId,
    authorizationUrl: options.authorizationUrl,
    tokenUrl: options.tokenUrl,
    clientId: options.clientId,
    clientSecretEncrypted: options.clientSecretEncrypted,
    scopes: options.scopes,
    apiKeyHeader: options.apiKeyHeader,
  });

  // 2. Create mcp_tool with provider reference
  await seedIntegrationTool(surreal, options.toolId, {
    name: options.toolName,
    toolkit: options.toolkit,
    description: options.description,
    inputSchema: options.inputSchema,
    providerId: options.providerId,
    workspaceId: options.workspaceId,
  });

  // 3. Create can_use edge
  await seedCanUseEdge(surreal, options.identityId, options.toolId);

  // 4. Create connected account
  await seedConnectedAccount(surreal, options.accountId, {
    identityId: options.identityId,
    providerId: options.providerId,
    workspaceId: options.workspaceId,
    accessTokenEncrypted: options.accessTokenEncrypted,
    refreshTokenEncrypted: options.refreshTokenEncrypted,
    tokenExpiresAt: options.tokenExpiresAt,
    apiKeyEncrypted: options.apiKeyEncrypted,
    basicUsername: options.basicUsername,
    basicPasswordEncrypted: options.basicPasswordEncrypted,
    scopes: options.scopes,
  });

  return {
    providerId: options.providerId,
    toolId: options.toolId,
    accountId: options.accountId,
  };
}

/**
 * Acceptance Tests: Tool Schema and Grants (US-3)
 *
 * Walking skeleton phase 1: The foundation. Admin creates tool definitions
 * and grants identities access via can_use edges.
 *
 * Traces: US-3, FR-1, FR-2, FR-3, AC-3
 * Driving ports:
 *   - POST /api/workspaces/:workspaceId/tools
 *   - GET /api/workspaces/:workspaceId/tools
 *   - POST /api/workspaces/:workspaceId/tools/:toolId/grants
 *   - GET /api/workspaces/:workspaceId/identities/:identityId/toolset
 *
 * Implementation sequence:
 *   1. Walking skeleton: create tool + grant + verify toolset  [ENABLED]
 *   2. Tool listing by workspace
 *   3. Tool filtering by toolkit and status
 *   4. Grant with rate limit
 *   5. Effective toolset deduplication
 *   6. Reject duplicate tool name in workspace
 *   7. Disabled tool excluded from toolset
 *   8. Grant removed clears toolset
 */
import { describe, expect, it } from "bun:test";
import {
  setupAcceptanceSuite,
  createTestUserWithMcp,
  seedMcpTool,
  seedBrainNativeTool,
  seedCanUseEdge,
  getToolsForWorkspace,
  getCanUseEdgesForIdentity,
} from "./tool-registry-test-kit";

const getRuntime = setupAcceptanceSuite("tool_registry_schema_grants");

// ---------------------------------------------------------------------------
// Walking Skeleton: Admin creates a tool and grants access to an agent
// ---------------------------------------------------------------------------
describe("Walking Skeleton: Admin grants agent access to a registered tool", () => {
  it("creates an mcp_tool and can_use edge, and the tool appears in identity toolset", async () => {
    const { baseUrl, surreal } = getRuntime();
    const user = await createTestUserWithMcp(baseUrl, surreal, `ws-us3-${crypto.randomUUID()}`);

    // Given admin has registered tool "search_entities" in the workspace
    const toolId = `tool-${crypto.randomUUID()}`;
    await seedBrainNativeTool(surreal, toolId, {
      name: "search_entities",
      description: "Search workspace entities by text query",
      inputSchema: { type: "object", properties: { query: { type: "string" } }, required: ["query"] },
      workspaceId: user.workspaceId,
    });

    // When admin grants "search_entities" to the agent identity
    await seedCanUseEdge(surreal, user.identityId, toolId);

    // Then the can_use edge exists with a granted_at timestamp
    const edges = await getCanUseEdgesForIdentity(surreal, user.identityId);
    expect(edges.length).toBe(1);
    expect(edges[0].granted_at).toBeDefined();

    // And the agent's effective toolset includes "search_entities"
    const tools = await getToolsForWorkspace(surreal, user.workspaceId);
    expect(tools.length).toBe(1);
    expect(tools[0].name).toBe("search_entities");
    expect(tools[0].status).toBe("active");
  }, 30_000);
});

