    // And policy "no-auto-merge" governs "github.merge_pr" with condition "requires_human_approval"
    const policyId = `pol-gov-${crypto.randomUUID()}`;
    await seedToolPolicy(surreal, policyId, {
      title: "no-auto-merge",
      workspaceId: user.workspaceId,
